import React, { useState } from 'react';
import { useNavigate, Navigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { createOrderRequest } from '../redux/slices/orderSlice';

const Checkout = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { items, totalAmount } = useSelector((state) => state.cart);
  const { isAuthenticated, customer, accountNumber } = useSelector((state) => state.auth);
  const { loading, error } = useSelector((state) => state.orders);

  const [formData, setFormData] = useState({
    shippingAddress: customer?.address || '',
    shippingCity: '',
    shippingState: '',
    customerPhone: customer?.phone || '',
    customerEmail: '',
    notes: '',
    paymentType: 'outright',
    installmentFrequency: 'weekly',
    installmentDuration: 4,
  });

  if (!isAuthenticated) {
    return <Navigate to="/login?redirect=checkout" />;
  }

  if (items.length === 0) {
    return <Navigate to="/cart" />;
  }

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    const orderData = {
      shippingAddress: formData.shippingAddress,
      shippingCity: formData.shippingCity,
      shippingState: formData.shippingState,
      customerPhone: formData.customerPhone,
      customerEmail: formData.customerEmail,
      notes: formData.notes,
      paymentType: formData.paymentType,
      accountNumber: accountNumber || customer?.phone,
    };

    if (formData.paymentType === 'installment') {
      orderData.installmentFrequency = formData.installmentFrequency;
      orderData.installmentDuration = parseInt(formData.installmentDuration);
    }

    dispatch(createOrderRequest({ orderData, navigate }));
  };

  const calculateInstallmentAmount = () => {
    if (formData.paymentType !== 'installment') return null;
    return Math.ceil(totalAmount / formData.installmentDuration);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <h1 className="text-2xl font-bold mb-8">Checkout</h1>

      {error && (
        <div className="bg-red-100 text-red-700 p-4 rounded-lg mb-6">{error}</div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Shipping & Payment Info */}
          <div className="lg:col-span-2 space-y-6">
            {/* Shipping Information */}
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-lg font-semibold mb-4">Shipping Information</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Shipping Address *
                  </label>
                  <textarea
                    name="shippingAddress"
                    value={formData.shippingAddress}
                    onChange={handleChange}
                    required
                    rows={3}
                    className="input-field"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">City</label>
                  <input
                    type="text"
                    name="shippingCity"
                    value={formData.shippingCity}
                    onChange={handleChange}
                    className="input-field"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">State</label>
                  <input
                    type="text"
                    name="shippingState"
                    value={formData.shippingState}
                    onChange={handleChange}
                    className="input-field"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Phone *</label>
                  <input
                    type="tel"
                    name="customerPhone"
                    value={formData.customerPhone}
                    onChange={handleChange}
                    required
                    className="input-field"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                  <input
                    type="email"
                    name="customerEmail"
                    value={formData.customerEmail}
                    onChange={handleChange}
                    className="input-field"
                  />
                </div>
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Order Notes (Optional)
                  </label>
                  <textarea
                    name="notes"
                    value={formData.notes}
                    onChange={handleChange}
                    rows={2}
                    className="input-field"
                    placeholder="Any special instructions..."
                  />
                </div>
              </div>
            </div>

            {/* Payment Options */}
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-lg font-semibold mb-4">Payment Option</h2>

              <div className="space-y-4">
                <label className="flex items-start p-4 border rounded-lg cursor-pointer hover:bg-gray-50">
                  <input
                    type="radio"
                    name="paymentType"
                    value="outright"
                    checked={formData.paymentType === 'outright'}
                    onChange={handleChange}
                    className="mt-1 mr-3"
                  />
                  <div>
                    <span className="font-medium">Outright Payment</span>
                    <p className="text-sm text-gray-600">
                      Pay the full amount of ₦{totalAmount?.toLocaleString()} now
                    </p>
                  </div>
                </label>

                <label className="flex items-start p-4 border rounded-lg cursor-pointer hover:bg-gray-50">
                  <input
                    type="radio"
                    name="paymentType"
                    value="installment"
                    checked={formData.paymentType === 'installment'}
                    onChange={handleChange}
                    className="mt-1 mr-3"
                  />
                  <div>
                    <span className="font-medium">Installment Payment</span>
                    <p className="text-sm text-gray-600">
                      Split your payment into weekly or monthly installments
                    </p>
                  </div>
                </label>
              </div>

              {formData.paymentType === 'installment' && (
                <div className="mt-6 p-4 bg-gray-50 rounded-lg">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        Payment Frequency
                      </label>
                      <select
                        name="installmentFrequency"
                        value={formData.installmentFrequency}
                        onChange={handleChange}
                        className="input-field"
                      >
                        <option value="weekly">Weekly</option>
                        <option value="monthly">Monthly</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        Duration ({formData.installmentFrequency === 'weekly' ? 'Weeks' : 'Months'})
                      </label>
                      <select
                        name="installmentDuration"
                        value={formData.installmentDuration}
                        onChange={handleChange}
                        className="input-field"
                      >
                        {formData.installmentFrequency === 'weekly' ? (
                          <>
                            <option value={4}>4 weeks</option>
                            <option value={8}>8 weeks</option>
                            <option value={12}>12 weeks</option>
                            <option value={24}>24 weeks</option>
                            <option value={52}>52 weeks</option>
                          </>
                        ) : (
                          <>
                            <option value={2}>2 months</option>
                            <option value={3}>3 months</option>
                            <option value={6}>6 months</option>
                            <option value={12}>12 months</option>
                          </>
                        )}
                      </select>
                    </div>
                  </div>
                  <div className="mt-4 p-3 bg-white rounded border">
                    <p className="text-sm text-gray-600">
                      You will pay approximately{' '}
                      <span className="font-semibold text-primary-600">
                        ₦{calculateInstallmentAmount()?.toLocaleString()}
                      </span>{' '}
                      per {formData.installmentFrequency === 'weekly' ? 'week' : 'month'} for{' '}
                      {formData.installmentDuration}{' '}
                      {formData.installmentFrequency === 'weekly' ? 'weeks' : 'months'}
                    </p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Order Summary */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow p-6 sticky top-20">
              <h2 className="text-lg font-semibold mb-4">Order Summary</h2>
              <div className="space-y-3 mb-4">
                {items.map((item) => (
                  <div key={item.productId} className="flex justify-between text-sm">
                    <span className="text-gray-600">
                      {item.productName} x {item.quantity}
                    </span>
                    <span>₦{item.subtotal?.toLocaleString()}</span>
                  </div>
                ))}
              </div>
              <div className="border-t pt-4 space-y-2">
                <div className="flex justify-between">
                  <span className="text-gray-600">Subtotal</span>
                  <span>₦{totalAmount?.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">Shipping</span>
                  <span className="text-green-600">Free</span>
                </div>
              </div>
              <div className="border-t mt-4 pt-4">
                <div className="flex justify-between text-lg font-semibold">
                  <span>Total</span>
                  <span>₦{totalAmount?.toLocaleString()}</span>
                </div>
              </div>
              <button
                type="submit"
                disabled={loading}
                className="btn-primary w-full mt-6"
              >
                {loading ? 'Processing...' : 'Place Order'}
              </button>
            </div>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Checkout;
